package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonNull_whenIsJsonNullTrue_returnsThisAsJsonNull() {
    JsonElement element = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(element.isJsonNull()).thenReturn(true);
    // Cast is safe because we mock it to return true for isJsonNull()
    JsonNull jsonNull = mock(JsonNull.class);
    // Spy the element so that casting to JsonNull is possible
    JsonElement spyElement = spy(element);
    doReturn(true).when(spyElement).isJsonNull();

    // Because getAsJsonNull casts (JsonNull) this, we must have spyElement be an instance of JsonNull
    // Mockito can't directly cast mock(JsonElement) to JsonNull, so create a subclass for test
    class JsonNullSubclass extends JsonElement implements JsonNull {
      @Override
      public JsonElement deepCopy() {
        return this;
      }
      @Override
      public boolean isJsonNull() {
        return true;
      }
    }
    JsonNullSubclass jsonNullSubclass = new JsonNullSubclass();

    JsonNull result = jsonNullSubclass.getAsJsonNull();

    assertSame(jsonNullSubclass, result);
  }

  @Test
  void getAsJsonNull_whenIsJsonNullFalse_throwsIllegalStateException() {
    JsonElement element = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(element.isJsonNull()).thenReturn(false);

    IllegalStateException exception = assertThrows(IllegalStateException.class, element::getAsJsonNull);
    assertTrue(exception.getMessage().startsWith("Not a JSON Null: "));
  }
}
